func (v ElementValue) ToObjectValue(ctx context.Context) (basetypes.ObjectValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	var issues attr.Value

	{
		issues = v.Issues
	}

	var props attr.Value

	{
		props = v.Props
	}

	var tagsVal basetypes.ListValue
	switch {
	case v.Tags.IsUnknown():
		tagsVal = types.ListUnknown(types.StringType)
	case v.Tags.IsNull():
		tagsVal = types.ListNull(types.StringType)
	default:
		var d diag.Diagnostics
		tagsVal, d = types.ListValue(types.StringType, v.Tags.Elements())
		diags.Append(d...)
	}

	if diags.HasError() {
		return types.ObjectUnknown(map[string]attr.Type{
			"_id":         basetypes.StringType{},
			"cld_account": basetypes.StringType{},
			"cld_id":      basetypes.StringType{},
			"cld_sync":    basetypes.BoolType{},
			"cld_type":    basetypes.StringType{},
			"color":       basetypes.StringType{},
			"icon":        basetypes.StringType{},
			"issues": basetypes.ListType{
				ElemType: IssuesValue{}.Type(ctx),
			},
			"name":   basetypes.StringType{},
			"parent": basetypes.StringType{},
			"props": PropsType{
				basetypes.ObjectType{
					AttrTypes: PropsValue{}.AttributeTypes(ctx),
				},
			},
			"tags": basetypes.ListType{
				ElemType: types.StringType,
			},
		}), diags
	}

	attributeTypes := map[string]attr.Type{
		"_id":         basetypes.StringType{},
		"cld_account": basetypes.StringType{},
		"cld_id":      basetypes.StringType{},
		"cld_sync":    basetypes.BoolType{},
		"cld_type":    basetypes.StringType{},
		"color":       basetypes.StringType{},
		"icon":        basetypes.StringType{},
		"issues": basetypes.ListType{
			ElemType: IssuesValue{}.Type(ctx),
		},
		"name":   basetypes.StringType{},
		"parent": basetypes.StringType{},
		"props": PropsType{
			basetypes.ObjectType{
				AttrTypes: PropsValue{}.AttributeTypes(ctx),
			},
		},
		"tags": basetypes.ListType{
			ElemType: types.StringType,
		},
	}

	if v.IsNull() {
		return types.ObjectNull(attributeTypes), diags
	}

	if v.IsUnknown() {
		return types.ObjectUnknown(attributeTypes), diags
	}

	objVal, diags := types.ObjectValue(
		attributeTypes,
		map[string]attr.Value{
			"_id":         v.UnderscoreId,
			"cld_account": v.CldAccount,
			"cld_id":      v.CldId,
			"cld_sync":    v.CldSync,
			"cld_type":    v.CldType,
			"color":       v.Color,
			"icon":        v.Icon,
			"issues":      issues,
			"name":        v.Name,
			"parent":      v.Parent,
			"props":       props,
			"tags":        tagsVal,
		})

	return objVal, diags
}

