func (v LinkValue) ToObjectValue(ctx context.Context) (basetypes.ObjectValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	var issues attr.Value

	{
		issues = v.Issues
	}

	var props attr.Value

	{
		props = v.Props
	}

	var tagsVal basetypes.ListValue
	switch {
	case v.Tags.IsUnknown():
		tagsVal = types.ListUnknown(types.StringType)
	case v.Tags.IsNull():
		tagsVal = types.ListNull(types.StringType)
	default:
		var d diag.Diagnostics
		tagsVal, d = types.ListValue(types.StringType, v.Tags.Elements())
		diags.Append(d...)
	}

	if diags.HasError() {
		return types.ObjectUnknown(map[string]attr.Type{
			"_id":             basetypes.StringType{},
			"cld_account":     basetypes.StringType{},
			"cld_id":          basetypes.StringType{},
			"cld_sync":        basetypes.BoolType{},
			"cld_type":        basetypes.StringType{},
			"connection_type": basetypes.StringType{},
			"issues": basetypes.ListType{
				ElemType: IssuesValue{}.Type(ctx),
			},
			"name":        basetypes.StringType{},
			"owner_ss_id": basetypes.StringType{},
			"props": PropsType{
				basetypes.ObjectType{
					AttrTypes: PropsValue{}.AttributeTypes(ctx),
				},
			},
			"tags": basetypes.ListType{
				ElemType: types.StringType,
			},
		}), diags
	}

	attributeTypes := map[string]attr.Type{
		"_id":             basetypes.StringType{},
		"cld_account":     basetypes.StringType{},
		"cld_id":          basetypes.StringType{},
		"cld_sync":        basetypes.BoolType{},
		"cld_type":        basetypes.StringType{},
		"connection_type": basetypes.StringType{},
		"issues": basetypes.ListType{
			ElemType: IssuesValue{}.Type(ctx),
		},
		"name":        basetypes.StringType{},
		"owner_ss_id": basetypes.StringType{},
		"props": PropsType{
			basetypes.ObjectType{
				AttrTypes: PropsValue{}.AttributeTypes(ctx),
			},
		},
		"tags": basetypes.ListType{
			ElemType: types.StringType,
		},
	}

	if v.IsNull() {
		return types.ObjectNull(attributeTypes), diags
	}

	if v.IsUnknown() {
		return types.ObjectUnknown(attributeTypes), diags
	}

	objVal, diags := types.ObjectValue(
		attributeTypes,
		map[string]attr.Value{
			"_id":             v.UnderscoreId,
			"cld_account":     v.CldAccount,
			"cld_id":          v.CldId,
			"cld_sync":        v.CldSync,
			"cld_type":        v.CldType,
			"connection_type": v.ConnectionType,
			"issues":          issues,
			"name":            v.Name,
			"owner_ss_id":     v.OwnerSsId,
			"props":           props,
			"tags":            tagsVal,
		})

	return objVal, diags
}

func (v LinkValue) Equal(o attr.Value) bool {
	other, ok := o.(LinkValue)

	if !ok {
		return false
	}

	if v.state != other.state {
		return false
	}

	if v.state != attr.ValueStateKnown {
		return true
	}

	if !v.UnderscoreId.Equal(other.UnderscoreId) {
		return false
	}

	if !v.CldAccount.Equal(other.CldAccount) {
		return false
	}

	if !v.CldId.Equal(other.CldId) {
		return false
	}

	if !v.CldSync.Equal(other.CldSync) {
		return false
	}

	if !v.CldType.Equal(other.CldType) {
		return false
	}

	if !v.ConnectionType.Equal(other.ConnectionType) {
		return false
	}

	if !v.Issues.Equal(other.Issues) {
		return false
	}

	if !v.Name.Equal(other.Name) {
		return false
	}

	if !v.OwnerSsId.Equal(other.OwnerSsId) {
		return false
	}

	if !v.Props.Equal(other.Props) {
		return false
	}

	if !v.Tags.Equal(other.Tags) {
		return false
	}

	return true
}

